#include <stdio.h>
#define MOD 1000000007
int main() {
    int N, m;
    scanf("%d %d", &N, &m);
    int d[m];
    for (int i = 0; i < m; i++) {
        scanf("%d", &d[i]);
    }
    int sum = 0;
    int start = 1;
    for (int i = 0; i < m; i++) {
        int end = start + d[i] - 1;
        int* screens = (int*) malloc((end - start + 1) * sizeof(int));
        for (int j = start; j <= end; j++) {
            screens[j - start] = j;
        }
        while (1) {
            int infected = 0;
            for (int j = end; j >= start; j--) {
                if (screens[j - start] != -1) {
                    infected = j;
                    break;
                }
            }
            if (infected == 0) break;
            screens[infected - start] = -1;
            for (int j = start; j < infected; j++) {
                int sum_val = 0;
                for (int k = start; k <= j; k++) {
                    if (screens[k - start] != -1) {
                        sum_val = (sum_val + screens[k - start]) % MOD;
                    }
                }
                screens[j - start] = sum_val;
            }
        }
        for (int j = start; j <= end; j++) {
            sum = (sum + screens[j - start]) % MOD;
        }
        free(screens);
        start = end + 1;
    }
    printf("%d\n", sum);
    return 0;
}

